import { defineStore } from "pinia";
import { api } from "@/api";
import { getStoredRole } from "@/utils/auth";

const SUMMARY_TTL = 15000;
const SUBJECT_TTL = 60000;
const PRIVATE_CHAT_TTL = 15000;
const ATTENDANCE_ADMIN_TTL = 15000;

const normalizeSubjectList = (response) => {
  const items = response?.data || [];
  return Array.isArray(items) ? items : [];
};

const normalizeSummaryList = (response) => {
  const items = response?.data || [];
  return Array.isArray(items) ? items : [];
};

const normalizePrivateChatList = (response) => {
  const items = response?.data || [];
  return Array.isArray(items) ? items : [];
};

export const useSidebar = defineStore("sidebar", {
  state: () => ({
    menu: [
      {
        name: "MENU",
        children: [
          {
            name: "Dashboard",
            icon: "bxs:dashboard",
            type: "default",
            url: "/dashboard",
          },
          {
            name: "Components",
            icon: "",
            type: "accordion",
            url: false,
            isChildren: true,
            children: [
              {
                name: "Alert",
                icon: false,
                type: "default",
              },
            ],
          },
        ],
      },
    ],
    openGroupsByRole: {},
    liveChatSubjects: [],
    liveChatSummaryItems: [],
    liveChatUnreadBySubject: {},
    liveChatPendingUnreadBySubject: {},
    liveChatUnreadCount: 0,
    liveChatSummaryLoadedAt: 0,
    liveChatSubjectsLoadedAt: 0,
    liveChatSummaryInFlight: null,
    liveChatSubjectsInFlight: null,
    privateChatSummaryItems: [],
    privateChatUnreadByUser: {},
    privateChatPendingUnreadByUser: {},
    privateChatUnreadCount: 0,
    privateChatSummaryLoadedAt: 0,
    privateChatSummaryInFlight: null,
    attendanceFacePendingCount: 0,
    attendanceFacePendingLoadedAt: 0,
    attendanceFacePendingInFlight: null,
  }),

  actions: {
    getOpenGroups(role) {
      return this.openGroupsByRole[role] || [];
    },

    setOpenGroups(role, groups = []) {
      this.openGroupsByRole = {
        ...this.openGroupsByRole,
        [role]: Array.isArray(groups) ? [...new Set(groups)] : [],
      };
    },

    toggleGroup(role, key) {
      const groups = this.getOpenGroups(role);
      if (groups.includes(key)) {
        this.setOpenGroups(role, groups.filter((item) => item !== key));
        return;
      }

      this.setOpenGroups(role, [...groups, key]);
    },

    clearOpenGroups(role) {
      if (!role) {
        return;
      }

      const next = { ...this.openGroupsByRole };
      delete next[role];
      this.openGroupsByRole = next;
    },

    recomputeLiveChatUnreadCount() {
      const subjectIds = new Set([
        ...Object.keys(this.liveChatUnreadBySubject || {}),
        ...Object.keys(this.liveChatPendingUnreadBySubject || {}),
      ]);

      this.liveChatUnreadCount = [...subjectIds].reduce((total, subjectId) => {
        const baseCount = Number(this.liveChatUnreadBySubject?.[subjectId] || 0);
        const pendingCount = Number(this.liveChatPendingUnreadBySubject?.[subjectId] || 0);
        return total + Math.max(baseCount, pendingCount);
      }, 0);
    },

    recomputePrivateChatUnreadCount() {
      const userIds = new Set([
        ...Object.keys(this.privateChatUnreadByUser || {}),
        ...Object.keys(this.privateChatPendingUnreadByUser || {}),
      ]);

      this.privateChatUnreadCount = [...userIds].reduce((total, userId) => {
        const baseCount = Number(this.privateChatUnreadByUser?.[userId] || 0);
        const pendingCount = Number(this.privateChatPendingUnreadByUser?.[userId] || 0);
        return total + Math.max(baseCount, pendingCount);
      }, 0);
    },

    applyLiveChatSummary(summaryItems = []) {
      const nextMap = {};
      const normalizedItems = Array.isArray(summaryItems) ? summaryItems : [];

      normalizedItems.forEach((item) => {
        const subjectId = Number(item?.subject_id || 0);
        if (!subjectId) {
          return;
        }

        nextMap[subjectId] = Number(item?.unread_count || 0);
      });

      this.liveChatSummaryItems = normalizedItems;
      this.liveChatUnreadBySubject = nextMap;
      this.liveChatSummaryLoadedAt = Date.now();
      this.recomputeLiveChatUnreadCount();
    },

    applyPrivateChatSummary(summaryItems = []) {
      const nextMap = {};
      const normalizedItems = Array.isArray(summaryItems) ? summaryItems : [];

      normalizedItems.forEach((item) => {
        const userId = Number(item?.user_id || 0);
        if (!userId) {
          return;
        }

        nextMap[userId] = Number(item?.unread_count || 0);
      });

      this.privateChatSummaryItems = normalizedItems;
      this.privateChatUnreadByUser = nextMap;
      this.privateChatSummaryLoadedAt = Date.now();
      this.recomputePrivateChatUnreadCount();
    },

    bumpLiveChatUnread(subjectId) {
      const normalizedSubjectId = Number(subjectId || 0);
      if (!normalizedSubjectId) {
        return;
      }

      this.liveChatPendingUnreadBySubject = {
        ...this.liveChatPendingUnreadBySubject,
        [normalizedSubjectId]: Number(this.liveChatPendingUnreadBySubject?.[normalizedSubjectId] || 0) + 1,
      };
      this.recomputeLiveChatUnreadCount();
    },

    bumpPrivateChatUnread(userId) {
      const normalizedUserId = Number(userId || 0);
      if (!normalizedUserId) {
        return;
      }

      this.privateChatPendingUnreadByUser = {
        ...this.privateChatPendingUnreadByUser,
        [normalizedUserId]: Number(this.privateChatPendingUnreadByUser?.[normalizedUserId] || 0) + 1,
      };
      this.recomputePrivateChatUnreadCount();
    },

    clearPendingLiveChatUnread() {
      if (Object.keys(this.liveChatPendingUnreadBySubject).length === 0) {
        return;
      }

      this.liveChatPendingUnreadBySubject = {};
      this.recomputeLiveChatUnreadCount();
    },

    clearPendingLiveChatUnreadBySubject(subjectId) {
      const normalizedSubjectId = Number(subjectId || 0);
      if (!normalizedSubjectId) {
        return;
      }

      if (!(normalizedSubjectId in this.liveChatPendingUnreadBySubject)) {
        return;
      }

      const nextPending = { ...this.liveChatPendingUnreadBySubject };
      delete nextPending[normalizedSubjectId];
      this.liveChatPendingUnreadBySubject = nextPending;
      this.recomputeLiveChatUnreadCount();
    },

    clearPendingPrivateChatUnread() {
      if (Object.keys(this.privateChatPendingUnreadByUser).length === 0) {
        return;
      }

      this.privateChatPendingUnreadByUser = {};
      this.recomputePrivateChatUnreadCount();
    },

    clearPendingPrivateChatUnreadByUser(userId) {
      const normalizedUserId = Number(userId || 0);
      if (!normalizedUserId) {
        return;
      }

      if (!(normalizedUserId in this.privateChatPendingUnreadByUser)) {
        return;
      }

      const nextPending = { ...this.privateChatPendingUnreadByUser };
      delete nextPending[normalizedUserId];
      this.privateChatPendingUnreadByUser = nextPending;
      this.recomputePrivateChatUnreadCount();
    },

    applyAttendanceFacePendingCount(count = 0) {
      this.attendanceFacePendingCount = Math.max(Number(count || 0), 0);
      this.attendanceFacePendingLoadedAt = Date.now();
    },

    bumpAttendanceFacePendingCount(count) {
      if (count !== undefined && count !== null) {
        this.applyAttendanceFacePendingCount(count);
        return;
      }
      this.applyAttendanceFacePendingCount(Number(this.attendanceFacePendingCount || 0) + 1);
    },

    async refreshAttendanceFacePendingCount({ force = false } = {}) {
      if (!force && this.attendanceFacePendingLoadedAt && Date.now() - this.attendanceFacePendingLoadedAt < ATTENDANCE_ADMIN_TTL) {
        return this.attendanceFacePendingCount;
      }

      if (this.attendanceFacePendingInFlight) {
        return this.attendanceFacePendingInFlight;
      }

      this.attendanceFacePendingInFlight = (async () => {
        try {
          const response = await api.get("/attendance/face-enrollment-requests/pending-count", {
            silentLoading: true,
          });
          this.applyAttendanceFacePendingCount(response?.data?.pending_count || 0);
        } catch (error) {
          // Keep the last known badge count if refresh fails.
        } finally {
          this.attendanceFacePendingInFlight = null;
        }
        return this.attendanceFacePendingCount;
      })();

      return this.attendanceFacePendingInFlight;
    },

    async refreshLiveChatSummary({ force = false } = {}) {
      const role = getStoredRole();
      if (!["GURU", "SISWA"].includes(role)) {
        this.applyLiveChatSummary([]);
        return [];
      }

      if (!force && this.liveChatSummaryLoadedAt && Date.now() - this.liveChatSummaryLoadedAt < SUMMARY_TTL) {
        return this.liveChatSummaryItems;
      }

      if (this.liveChatSummaryInFlight) {
        return this.liveChatSummaryInFlight;
      }

      this.liveChatSummaryInFlight = (async () => {
        try {
          const summaryItems = normalizeSummaryList(await api.get("/learning/chat/summary", {
            silentLoading: true,
          }));
          this.applyLiveChatSummary(summaryItems);
        } catch (error) {
          // Keep previous summary if the request fails.
        } finally {
          this.liveChatSummaryInFlight = null;
        }

        return this.liveChatSummaryItems;
      })();

      return this.liveChatSummaryInFlight;
    },

    async refreshPrivateChatSummary({ force = false } = {}) {
      const role = getStoredRole();
      if (!["ADMIN", "ADMIN_SPMB", "KOPERASI", "BENDAHARA", "GURU", "SISWA"].includes(role)) {
        this.applyPrivateChatSummary([]);
        return [];
      }

      if (!force && this.privateChatSummaryLoadedAt && Date.now() - this.privateChatSummaryLoadedAt < PRIVATE_CHAT_TTL) {
        return this.privateChatSummaryItems;
      }

      if (this.privateChatSummaryInFlight) {
        return this.privateChatSummaryInFlight;
      }

      this.privateChatSummaryInFlight = (async () => {
        try {
          const summaryItems = normalizePrivateChatList(await api.get("/private-chat/summary", {
            silentLoading: true,
          }));
          this.applyPrivateChatSummary(summaryItems);
        } catch (error) {
          // Keep previous summary if the request fails.
        } finally {
          this.privateChatSummaryInFlight = null;
        }

        return this.privateChatSummaryItems;
      })();

      return this.privateChatSummaryInFlight;
    },

    async refreshLiveChatSubjects(role, { force = false } = {}) {
      const normalizedRole = String(role || "").toUpperCase();
      const endpoint = normalizedRole === "GURU" ? "/learning/subjects/teacher" : "/learning/subjects/student";

      if (!["GURU", "SISWA"].includes(normalizedRole)) {
        this.liveChatSubjects = [];
        return [];
      }

      if (!force && this.liveChatSubjectsLoadedAt && Date.now() - this.liveChatSubjectsLoadedAt < SUBJECT_TTL) {
        return this.liveChatSubjects;
      }

      if (this.liveChatSubjectsInFlight) {
        return this.liveChatSubjectsInFlight;
      }

      this.liveChatSubjectsInFlight = (async () => {
        try {
          const response = await api.get(endpoint, {
            silentLoading: true,
          });
          this.liveChatSubjects = normalizeSubjectList(response);
          this.liveChatSubjectsLoadedAt = Date.now();
        } catch (error) {
          if (!this.liveChatSubjects.length) {
            this.liveChatSubjects = [];
          }
        } finally {
          this.liveChatSubjectsInFlight = null;
        }

        return this.liveChatSubjects;
      })();

      return this.liveChatSubjectsInFlight;
    },

    invalidateLiveChatCache() {
      this.liveChatSummaryLoadedAt = 0;
      this.liveChatSubjectsLoadedAt = 0;
      this.privateChatSummaryLoadedAt = 0;
    },
  },
});
